/**
 * Gmail Auto Labeler - 자동 메일 분류 스크립트
 * 
 * 기능:
 * 1. 새로운 메일을 자동으로 분류
 * 2. 중요도에 따라 라벨 부여
 * 3. 긴급 메일은 별표 추가
 * 
 * 설정 방법:
 * 1. Google Apps Script (script.google.com)에 이 코드 붙여넣기
 * 2. CONFIG 섹션을 본인 상황에 맞게 수정
 * 3. 트리거 설정: autoLabelEmails 함수를 15분마다 실행
 */

// ==================== CONFIG ====================

const CONFIG = {
  // 처리할 메일 개수 (한 번에)
  BATCH_SIZE: 50,

  // 라벨 이름 설정
  LABELS: {
    URGENT: 'Work/Urgent',
    IMPORTANT: 'Work/Important',
    TEAM: 'Work/Team',
    NEWSLETTER: 'Auto/Newsletters',
    PROMOTION: 'Auto/Promotions',
    PERSONAL: 'Personal',
    TO_REVIEW: 'To Review'
  },

  // 긴급 메일 키워드
  URGENT_KEYWORDS: [
    '긴급', 'urgent', 'asap', '즉시', 'emergency',
    'critical', '중요', 'important'
  ],

  // 업무 도메인 (회사 이메일)
  WORK_DOMAINS: [
    '@lgpri.com',
    '@lg.com',
    // 여기에 회사 도메인 추가
  ],

  // 뉴스레터 발신자 패턴
  NEWSLETTER_PATTERNS: [
    'newsletter@',
    'noreply@',
    'no-reply@',
    'digest@',
    'updates@'
  ],

  // 프로모션 발신자 패턴
  PROMOTION_PATTERNS: [
    'promo@',
    'marketing@',
    'deals@',
    'offers@',
    'sales@'
  ]
};

// ==================== MAIN FUNCTIONS ====================

/**
 * 메인 함수: 받은편지함의 읽지 않은 메일을 자동으로 분류
 */
function autoLabelEmails() {
  try {
    console.log('Starting email auto-labeling...');

    // 읽지 않은 메일 가져오기
    const threads = GmailApp.getInboxThreads(0, CONFIG.BATCH_SIZE);
    console.log(`Found ${threads.length} threads to process`);

    let processed = 0;
    let labeled = 0;

    threads.forEach(thread => {
      const messages = thread.getMessages();
      const latestMessage = messages[messages.length - 1];

      // 이미 읽은 메일은 건너뛰기
      if (!latestMessage.isUnread()) {
        return;
      }

      processed++;

      // 메일 분석 및 라벨링
      const labels = analyzeAndLabel(latestMessage, thread);

      if (labels.length > 0) {
        labeled++;
        console.log(`Labeled: ${latestMessage.getSubject()} -> ${labels.join(', ')}`);
      }
    });

    console.log(`Processed: ${processed}, Labeled: ${labeled}`);

  } catch (error) {
    console.error('Error in autoLabelEmails:', error);
    sendErrorNotification(error);
  }
}

/**
 * 메일을 분석하고 적절한 라벨을 부여
 */
function analyzeAndLabel(message, thread) {
  const from = message.getFrom();
  const subject = message.getSubject();
  const body = message.getPlainBody();
  const appliedLabels = [];

  // 1. 긴급 메일 체크
  if (isUrgent(subject, body)) {
    applyLabel(thread, CONFIG.LABELS.URGENT);
    thread.markImportant();
    thread.addLabel(GmailApp.getUserLabelByName('STARRED') || createLabel('STARRED'));
    appliedLabels.push(CONFIG.LABELS.URGENT);
  }

  // 2. 업무 메일 체크
  if (isWorkEmail(from)) {
    applyLabel(thread, CONFIG.LABELS.TEAM);
    appliedLabels.push(CONFIG.LABELS.TEAM);
  }

  // 3. 뉴스레터 체크
  if (isNewsletter(from)) {
    applyLabel(thread, CONFIG.LABELS.NEWSLETTER);
    thread.moveToArchive();
    appliedLabels.push(CONFIG.LABELS.NEWSLETTER);
  }

  // 4. 프로모션 체크
  if (isPromotion(from, subject)) {
    applyLabel(thread, CONFIG.LABELS.PROMOTION);
    appliedLabels.push(CONFIG.LABELS.PROMOTION);
  }

  // 5. 개인 메일 체크
  if (!isWorkEmail(from) && !isNewsletter(from) && !isPromotion(from, subject)) {
    applyLabel(thread, CONFIG.LABELS.PERSONAL);
    appliedLabels.push(CONFIG.LABELS.PERSONAL);
  }

  return appliedLabels;
}

// ==================== HELPER FUNCTIONS ====================

/**
 * 긴급 메일 판단
 */
function isUrgent(subject, body) {
  const text = (subject + ' ' + body).toLowerCase();
  return CONFIG.URGENT_KEYWORDS.some(keyword => 
    text.includes(keyword.toLowerCase())
  );
}

/**
 * 업무 메일 판단
 */
function isWorkEmail(from) {
  return CONFIG.WORK_DOMAINS.some(domain => 
    from.toLowerCase().includes(domain.toLowerCase())
  );
}

/**
 * 뉴스레터 판단
 */
function isNewsletter(from) {
  return CONFIG.NEWSLETTER_PATTERNS.some(pattern => 
    from.toLowerCase().includes(pattern.toLowerCase())
  );
}

/**
 * 프로모션 메일 판단
 */
function isPromotion(from, subject) {
  const text = (from + ' ' + subject).toLowerCase();
  return CONFIG.PROMOTION_PATTERNS.some(pattern => 
    text.includes(pattern.toLowerCase())
  );
}

/**
 * 라벨 적용 (없으면 생성)
 */
function applyLabel(thread, labelName) {
  let label = GmailApp.getUserLabelByName(labelName);

  if (!label) {
    label = createLabel(labelName);
  }

  thread.addLabel(label);
}

/**
 * 라벨 생성 (계층 구조 지원)
 */
function createLabel(labelName) {
  console.log(`Creating label: ${labelName}`);

  // 부모 라벨이 있는 경우 (예: Work/Urgent)
  const parts = labelName.split('/');
  let currentPath = '';

  parts.forEach((part, index) => {
    currentPath += (index > 0 ? '/' : '') + part;

    if (!GmailApp.getUserLabelByName(currentPath)) {
      GmailApp.createLabel(currentPath);
    }
  });

  return GmailApp.getUserLabelByName(labelName);
}

/**
 * 에러 알림 전송
 */
function sendErrorNotification(error) {
  const subject = '⚠️ Gmail Auto Labeler Error';
  const body = `
    An error occurred in Gmail Auto Labeler:

    Error: ${error.message}
    Stack: ${error.stack}

    Time: ${new Date().toLocaleString()}
  `;

  GmailApp.sendEmail(Session.getActiveUser().getEmail(), subject, body);
}

// ==================== UTILITY FUNCTIONS ====================

/**
 * 모든 라벨 생성 (초기 설정용)
 */
function createAllLabels() {
  console.log('Creating all labels...');

  Object.values(CONFIG.LABELS).forEach(labelName => {
    if (!GmailApp.getUserLabelByName(labelName)) {
      createLabel(labelName);
      console.log(`Created: ${labelName}`);
    }
  });

  console.log('All labels created!');
}

/**
 * 통계 확인
 */
function getEmailStats() {
  const stats = {
    total: GmailApp.getInboxThreads().length,
    unread: GmailApp.getInboxUnreadCount(),
    labels: {}
  };

  Object.entries(CONFIG.LABELS).forEach(([key, labelName]) => {
    const label = GmailApp.getUserLabelByName(labelName);
    if (label) {
      stats.labels[labelName] = label.getThreads().length;
    }
  });

  console.log('Email Statistics:');
  console.log(JSON.stringify(stats, null, 2));

  return stats;
}

/**
 * 테스트 실행 (5개만 처리)
 */
function testRun() {
  const originalBatchSize = CONFIG.BATCH_SIZE;
  CONFIG.BATCH_SIZE = 5;

  console.log('Running test with 5 emails...');
  autoLabelEmails();

  CONFIG.BATCH_SIZE = originalBatchSize;
  console.log('Test completed!');
}

// ==================== SETUP INSTRUCTIONS ====================

/**
 * 초기 설정 가이드
 * 
 * 1. 이 스크립트를 Google Apps Script에 복사
 * 2. CONFIG 섹션 수정:
 *    - WORK_DOMAINS: 회사 이메일 도메인 추가
 *    - URGENT_KEYWORDS: 긴급 키워드 커스터마이징
 *    - LABELS: 원하는 라벨 이름 설정
 * 
 * 3. 첫 실행:
 *    - createAllLabels() 함수 실행 → 모든 라벨 생성
 *    - testRun() 함수 실행 → 5개 메일로 테스트
 * 
 * 4. 트리거 설정:
 *    - 왼쪽 메뉴 "트리거" 클릭
 *    - "트리거 추가" 클릭
 *    - 함수: autoLabelEmails
 *    - 이벤트 소스: 시간 기반
 *    - 시간 간격: 15분마다
 * 
 * 5. 권한 승인:
 *    - 처음 실행 시 권한 요청
 *    - Gmail 읽기/쓰기 권한 승인
 */

