/**
 * Gmail to Notion - 중요 메일을 Notion으로 자동 전송
 * 
 * 기능:
 * 1. 긴급/중요 메일을 Notion 데이터베이스로 전송
 * 2. 작업 항목으로 자동 생성
 * 3. 우선순위 및 마감일 자동 설정
 * 
 * 설정 방법:
 * 1. Notion Integration 생성 (https://www.notion.so/my-integrations)
 * 2. Integration Token과 Database ID를 아래 CONFIG에 입력
 * 3. 트리거 설정: syncImportantEmailsToNotion 함수를 1시간마다 실행
 */

// ==================== CONFIG ====================

const NOTION_CONFIG = {
  // Notion Integration Token (https://www.notion.so/my-integrations)
  TOKEN: 'YOUR_NOTION_INTEGRATION_TOKEN_HERE',

  // Notion Database ID (데이터베이스 URL에서 복사)
  // URL 형식: https://notion.so/workspace/DATABASE_ID?v=...
  DATABASE_ID: 'YOUR_DATABASE_ID_HERE',

  // 동기화할 라벨 (이 라벨이 있는 메일만 Notion으로 전송)
  SYNC_LABELS: [
    'Work/Urgent',
    'Work/Important',
    'To Review'
  ],

  // 처리할 메일 개수 (한 번에)
  BATCH_SIZE: 20,

  // 마감일 자동 설정 (일 단위)
  DEFAULT_DUE_DAYS: 3
};

// ==================== MAIN FUNCTIONS ====================

/**
 * 메인 함수: 중요 메일을 Notion으로 동기화
 */
function syncImportantEmailsToNotion() {
  try {
    console.log('Starting Gmail to Notion sync...');

    let totalSynced = 0;

    // 각 라벨별로 처리
    NOTION_CONFIG.SYNC_LABELS.forEach(labelName => {
      const synced = syncLabelToNotion(labelName);
      totalSynced += synced;
    });

    console.log(`Total emails synced to Notion: ${totalSynced}`);

  } catch (error) {
    console.error('Error in syncImportantEmailsToNotion:', error);
    sendErrorNotification('Gmail to Notion', error);
  }
}

/**
 * 특정 라벨의 메일을 Notion으로 동기화
 */
function syncLabelToNotion(labelName) {
  const label = GmailApp.getUserLabelByName(labelName);

  if (!label) {
    console.log(`Label not found: ${labelName}`);
    return 0;
  }

  // 읽지 않은 메일만 가져오기
  const threads = label.getThreads(0, NOTION_CONFIG.BATCH_SIZE);
  let synced = 0;

  threads.forEach(thread => {
    const messages = thread.getMessages();
    const latestMessage = messages[messages.length - 1];

    // 이미 처리된 메일은 건너뛰기 (특수 라벨 확인)
    if (thread.getLabels().some(l => l.getName() === 'Synced to Notion')) {
      return;
    }

    // Notion으로 전송
    const success = createNotionPage(latestMessage, thread, labelName);

    if (success) {
      // 동기화 완료 라벨 추가
