 * 설정 방법:
 * 1. CONFIG 섹션을 본인 상황에 맞게 수정
 * 2. 트리거 설정: dailyCleanup 함수를 매일 자정에 실행
 * 3. 트리거 설정: weeklyReport 함수를 매주 월요일 오전 9시에 실행
 */

// ==================== CONFIG ====================

const CLEANER_CONFIG = {
  // 삭제 기준 (일 단위)
  DELETE_AFTER_DAYS: {
    PROMOTIONS: 30,      // 프로모션 메일
    NEWSLETTERS_READ: 7, // 읽은 뉴스레터
    SOCIAL: 60,          // 소셜 알림
    SPAM: 1              // 스팸
  },

  // 아카이브 기준 (일 단위)
  ARCHIVE_AFTER_DAYS: {
    NEWSLETTERS_UNREAD: 30, // 읽지 않은 뉴스레터
    UPDATES_READ: 14        // 읽은 업데이트
  },

  // 대용량 첨부파일 기준 (MB)
  LARGE_ATTACHMENT_SIZE: 10,

  // 처리할 메일 개수 (한 번에)
  BATCH_SIZE: 100,

  // 드라이 런 모드 (true면 실제 삭제하지 않고 로그만 출력)
  DRY_RUN: false,

  // 주간 리포트 발송 이메일
  REPORT_EMAIL: Session.getActiveUser().getEmail()
};

// ==================== MAIN FUNCTIONS ====================

/**
 * 일일 정리 작업
 */
function dailyCleanup() {
  try {
    console.log('Starting daily cleanup...');

    const stats = {
      deleted: 0,
      archived: 0,
      processed: 0
    };

    // 1. 오래된 프로모션 메일 삭제
    stats.deleted += deleteOldPromotions();

    // 2. 읽은 뉴스레터 아카이브
    stats.archived += archiveReadNewsletters();

    // 3. 오래된 소셜 알림 삭제
    stats.deleted += deleteOldSocialNotifications();

    // 4. 스팸 메일 정리
    stats.deleted += cleanSpam();

    console.log('Daily cleanup completed:', JSON.stringify(stats));

    // 정리 완료 알림 (결과가 있을 때만)
    if (stats.deleted > 0 || stats.archived > 0) {
      sendCleanupNotification(stats);
    }

  } catch (error) {
    console.error('Error in dailyCleanup:', error);
    sendErrorNotification('Inbox Cleaner', error);
  }
}

/**
 * 오래된 프로모션 메일 삭제
 */
function deleteOldPromotions() {
  const daysAgo = CLEANER_CONFIG.DELETE_AFTER_DAYS.PROMOTIONS;
  const query = `category:promotions older_than:${daysAgo}d`;

  return processThreads(query, 'delete', 'Old Promotions');
}

/**
 * 읽은 뉴스레터 아카이브
 */
function archiveReadNewsletters() {
  const daysAgo = CLEANER_CONFIG.DELETE_AFTER_DAYS.NEWSLETTERS_READ;
  const label = GmailApp.getUserLabelByName('Auto/Newsletters');

  if (!label) {
    console.log('Newsletter label not found');
    return 0;
  }

  const query = `label:${label.getName()} is:read older_than:${daysAgo}d`;

  return processThreads(query, 'archive', 'Read Newsletters');
}

/**
 * 오래된 소셜 알림 삭제
 */
function deleteOldSocialNotifications() {
  const daysAgo = CLEANER_CONFIG.DELETE_AFTER_DAYS.SOCIAL;
  const query = `category:social older_than:${daysAgo}d`;

  return processThreads(query, 'delete', 'Old Social');
}

/**
 * 스팸 메일 정리
 */
function cleanSpam() {
  const daysAgo = CLEANER_CONFIG.DELETE_AFTER_DAYS.SPAM;
  const query = `in:spam older_than:${daysAgo}d`;

  return processThreads(query, 'delete', 'Spam');
}

/**
 * 쓰레드 처리 (삭제 또는 아카이브)
 */
function processThreads(query, action, label) {
  try {
    const threads = GmailApp.search(query, 0, CLEANER_CONFIG.BATCH_SIZE);
    console.log(`Found ${threads.length} threads for ${label} (${action})`);

    if (threads.length === 0) {
      return 0;
    }

    if (CLEANER_CONFIG.DRY_RUN) {
      console.log(`[DRY RUN] Would ${action} ${threads.length} threads`);
      return threads.length;
    }

    if (action === 'delete') {
      threads.forEach(thread => thread.moveToTrash());
    } else if (action === 'archive') {
      threads.forEach(thread => thread.moveToArchive());
    }

    console.log(`${action}d ${threads.length} threads (${label})`);
    return threads.length;

  } catch (error) {
    console.error(`Error processing threads (${label}):`, error);
    return 0;
  }
}

// ==================== WEEKLY REPORT ====================

/**
 * 주간 정리 리포트
 */
function weeklyReport() {
  try {
    console.log('Generating weekly report...');

    const stats = {
      inbox: getInboxStats(),
      categories: getCategoryStats(),
      largeAttachments: findLargeAttachments(),
      topSenders: getTopSenders()
    };

    sendWeeklyReport(stats);

  } catch (error) {
    console.error('Error in weeklyReport:', error);
    sendErrorNotification('Weekly Report', error);
  }
}

/**
 * 받은편지함 통계
 */
function getInboxStats() {
  return {
    total: GmailApp.getInboxThreads().length,
    unread: GmailApp.getInboxUnreadCount(),
    starred: GmailApp.getStarredThreads().length
  };
}

/**
 * 카테고리별 통계
 */
function getCategoryStats() {
  const categories = ['promotions', 'social', 'updates', 'forums'];
  const stats = {};

  categories.forEach(category => {
    const threads = GmailApp.search(`category:${category}`, 0, 1);
    stats[category] = threads.length;
  });

  return stats;
}

/**
 * 대용량 첨부파일 찾기
 */
function findLargeAttachments() {
  const sizeBytes = CLEANER_CONFIG.LARGE_ATTACHMENT_SIZE * 1024 * 1024;
  const query = `has:attachment larger:${CLEANER_CONFIG.LARGE_ATTACHMENT_SIZE}M`;
  const threads = GmailApp.search(query, 0, 10);

  return threads.map(thread => {
    const message = thread.getMessages()[0];
    return {
      subject: message.getSubject(),
      from: message.getFrom(),
      date: message.getDate(),
      size: estimateSize(thread)
    };
  });
}

/**
 * 메일 크기 추정
 */
function estimateSize(thread) {
  const messages = thread.getMessages();
  let totalSize = 0;

  messages.forEach(message => {
    const attachments = message.getAttachments();
    attachments.forEach(attachment => {
      totalSize += attachment.getSize();
    });
  });

  return (totalSize / (1024 * 1024)).toFixed(2) + ' MB';
}

/**
 * 상위 발신자 분석
 */
function getTopSenders() {
  const senders = {};
  const threads = GmailApp.getInboxThreads(0, 100);

  threads.forEach(thread => {
    const messages = thread.getMessages();
    messages.forEach(message => {
      const from = extractEmail(message.getFrom());
      senders[from] = (senders[from] || 0) + 1;
    });
  });

  // 상위 10개 정렬
  return Object.entries(senders)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10)
    .map(([email, count]) => ({ email, count }));
}

/**
 * 이메일 주소 추출
 */
function extractEmail(fromString) {
  const emailMatch = fromString.match(/<(.+?)>/);
  return emailMatch ? emailMatch[1] : fromString;
}

// ==================== NOTIFICATION FUNCTIONS ====================

/**
 * 정리 완료 알림
 */
function sendCleanupNotification(stats) {
  const subject = '✅ Gmail 자동 정리 완료';
  const body = `
오늘의 Gmail 자동 정리가 완료되었습니다.

📊 정리 결과:
- 삭제된 메일: ${stats.deleted}개
- 아카이브된 메일: ${stats.archived}개
- 처리된 메일: ${stats.processed}개

시간: ${new Date().toLocaleString()}

---
이 메일은 Inbox Cleaner에서 자동으로 발송되었습니다.
  `;

  GmailApp.sendEmail(CLEANER_CONFIG.REPORT_EMAIL, subject, body);
}

