  const subject = '🗑️ Gmail 휴지통 비우기 알림';
  const body = `
휴지통에 ${GmailApp.getTrashThreads().length}개의 메일이 있습니다.

Gmail에서 수동으로 휴지통을 비워주세요:
1. Gmail 열기
2. 왼쪽 메뉴에서 "휴지통" 클릭
3. "휴지통 비우기" 클릭

참고: 휴지통의 메일은 30일 후 자동으로 삭제됩니다.
  `;

  GmailApp.sendEmail(CLEANER_CONFIG.REPORT_EMAIL, subject, body);
}

