  const threads = GmailApp.search(query, 0, 10);

  return threads.map(thread => {
    const message = thread.getMessages()[0];
    return {
      subject: message.getSubject(),
      from: message.getFrom(),
      date: message.getDate(),
      size: estimateSize(thread)
    };
  });
}

/**
 * 메일 크기 추정
 */
function estimateSize(thread) {
  const messages = thread.getMessages();
  let totalSize = 0;

  messages.forEach(message => {
    const attachments = message.getAttachments();
    attachments.forEach(attachment => {
      totalSize += attachment.getSize();
    });
  });

  return (totalSize / (1024 * 1024)).toFixed(2) + ' MB';
}

/**
 * 상위 발신자 분석
 */
function getTopSenders() {
  const senders = {};
  const threads = GmailApp.getInboxThreads(0, 100);

  threads.forEach(thread => {
    const messages = thread.getMessages();
    messages.forEach(message => {
      const from = extractEmail(message.getFrom());
      senders[from] = (senders[from] || 0) + 1;
    });
  });

  // 상위 10개 정렬
  return Object.entries(senders)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10)
    .map(([email, count]) => ({ email, count }));
}

/**
 * 이메일 주소 추출
 */
function extractEmail(fromString) {
  const emailMatch = fromString.match(/<(.+?)>/);
  return emailMatch ? emailMatch[1] : fromString;
}

