  });

  body += `
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

💾 대용량 첨부파일 (상위 ${stats.largeAttachments.length}개)
`;

  stats.largeAttachments.forEach((item, index) => {
    body += `
${index + 1}. ${item.subject}
   From: ${item.from}
   Size: ${item.size}
`;
  });

  body += `
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

👥 상위 발신자 (Top 10)
`;

  stats.topSenders.forEach((sender, index) => {
    body += `${index + 1}. ${sender.email}: ${sender.count}개\n`;
  });

  body += `
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

💡 권장 사항:
`;

  // 권장 사항 생성
  if (stats.inbox.unread > 50) {
    body += `- ⚠️ 읽지 않은 메일이 ${stats.inbox.unread}개입니다. 정리가 필요합니다.\n`;
  }

  if (stats.largeAttachments.length > 0) {
    body += `- 💾 대용량 첨부파일이 ${stats.largeAttachments.length}개 있습니다. Google Drive로 백업을 고려하세요.\n`;
  }

  // 자주 오는 발신자 구독 해제 제안
  const frequentSender = stats.topSenders[0];
  if (frequentSender && frequentSender.count > 10) {
    body += `- 📧 ${frequentSender.email}에서 주간 ${frequentSender.count}개 메일을 받고 있습니다. 필터 설정을 고려하세요.\n`;
  }

  body += `
---
이 리포트는 매주 월요일에 자동으로 발송됩니다.
`;

  GmailApp.sendEmail(CLEANER_CONFIG.REPORT_EMAIL, subject, body);
